Javascript.miscCode:

function TimeRemainingUnits() {}
TimeRemainingUnits.dataBinding = "/ds/EnterVariableData/TrialNotice/timeRemainingUnits";
TimeRemainingUnits.tabIndex = __tabIdx++;
TimeRemainingUnits.helpText = "Select unit time";
TimeRemainingUnits.mandatoryOn = [TimeRemaining.dataBinding];
TimeRemainingUnits.isMandatory = function()
{	var val = Services.getValue(TimeRemaining.dataBinding);
	return( null != val && "" != val );
}	
TimeRemainingUnits.enableOn = [TimeRemaining.dataBinding];
TimeRemainingUnits.isEnabled = function(){ return TimeRemaining.isEnabled();}
TimeRemainingUnits.isTemporary = function(){  return true; }	
TimeRemainingUnits.logicOn = [TimeRemaining.dataBinding];
TimeRemainingUnits.logic = function()
{	if(!TimeRemaining.isEnabled())
	Services.setValue(TimeRemainingUnits.dataBinding,"");			
}
